"use client"

import { useState, useEffect, useCallback } from "react"
import { useRouter, useSearchParams } from "next/navigation"
import {
  GitCompare,
  ArrowLeftRight,
  Loader2,
  AlertCircle,
} from "lucide-react"
import type { TestExecution, ComparisonResult } from "@/lib/types"
import { ExecutionSelector } from "@/components/dashboard/execution-selector"
import { ComparisonSummaryCards } from "@/components/dashboard/comparison-summary-cards"
import { TestDiffTable } from "@/components/dashboard/test-diff-table"

interface CompareClientProps {
  executions: TestExecution[]
  branches: string[]
  suites: string[]
  initialBaseline: number | null
  initialCurrent: number | null
  initialBaselineBranch?: string
  initialCurrentBranch?: string
  initialSuite?: string
}

export function CompareClient({
  executions,
  branches,
  suites,
  initialBaseline,
  initialCurrent,
  initialBaselineBranch,
  initialCurrentBranch,
  initialSuite,
}: CompareClientProps) {
  const router = useRouter()
  const searchParams = useSearchParams()

  const [baselineId, setBaselineId] = useState<number | null>(initialBaseline)
  const [currentId, setCurrentId] = useState<number | null>(initialCurrent)
  const [comparison, setComparison] = useState<ComparisonResult | null>(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

// If branch names provided, resolve to latest execution IDs
if (baselineBranch && !resolvedBaselineId) {
  const baselineExecution = await db.getLatestExecutionByBranch(baselineBranch, suite)
  if (!baselineExecution) {
    return NextResponse.json(
      { error: `No execution found for baseline branch: ${baselineBranch}` },
      { status: 404 }
    )
  }
  resolvedBaselineId = baselineExecution.id
}

if (currentBranch && !resolvedCurrentId) {
  const currentExecution = await db.getLatestExecutionByBranch(currentBranch, suite)
  if (!currentExecution) {
    return NextResponse.json(
      { error: `No execution found for current branch: ${currentBranch}` },
      { status: 404 }
    )
  }
  resolvedCurrentId = currentExecution.id
}

import { Suspense } from "react"
import { CompareClient } from "./compare-client"
import { getSessionContext } from "@/lib/session-context"
import { getQueriesForOrg } from "@/lib/db"
import { redirect } from "next/navigation"

export const dynamic = "force-dynamic"

interface ComparePageProps {
  searchParams: Promise<{
    baseline?: string
    current?: string
    baseline_branch?: string
    current_branch?: string
    suite?: string
  }>
}

async function CompareContent({ searchParams }: ComparePageProps) {
  const context = await getSessionContext()
  if (!context) {
    redirect("/auth/signin")
  }

  const db = getQueriesForOrg(context.organizationId)
  const params = await searchParams

  const [executions, branchStats, suiteStats] = await Promise.all([
    db.getExecutions(50),
    db.getBranches(),
    db.getSuites(),
  ])

  // Extract names for backwards compatibility
  const branches = branchStats.map((b) => b.branch)
  const suites = suiteStats.map((s) => s.suite)

  const initialBaseline = params.baseline ? parseInt(params.baseline, 10) : null
  const initialCurrent = params.current ? parseInt(params.current, 10) : null

  return (
    <CompareClient
      executions={executions}
      branches={branches}
      suites={suites}
      initialBaseline={initialBaseline}
      initialCurrent={initialCurrent}
      initialBaselineBranch={params.baseline_branch}
      initialCurrentBranch={params.current_branch}
      initialSuite={params.suite}
    />
  )
}

